#include<bits/stdc++.h>
using namespace std;
int exgcd(int a,int b,int &x,int &y)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    int g=exgcd(b,a%b,x,y);
    int tx=x;
    x=y;
    y=tx-(a/b)*y;
    return g;
}
int n,c[101],p[101],l[101];
bool check(int x)
{
    for(int i=1;i<=n;i++)
    {
        for(int j=i+1;j<=n;j++)
        {
            int a=p[i]-p[j],b=x,c=::c[j]-::c[i];
            int x,y;
            int g=exgcd(a,b,x,y);
            if(c%g!=0)
            {
                continue;
            }
            a/=g;
            b/=g;
            c/=g;
            b=abs(b);
            x=(x*c%b+b)%b;
            if(x<=l[i]&&x<=l[j])
            {
                return false;
            }
        }
    }
    return true;
}
int main()
{
    scanf("%d",&n);
    int max1=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&c[i],&p[i],&l[i]);
        max1=max(max1,c[i]);
    }
    for(int i=max1;;i++)
    {
        if(check(i))
        {
            printf("%d",i);
            return 0;
        }
    }
    return 0;
}
